import{_ as t,c as a,q as o,o as i}from"./chunks/framework.CgQGrdLP.js";const p="/assets/deepin-meetup-02.oJzFuEFv.jpg",n="/assets/deepin-meetup-03.siMaqVGL.jpg",r="/assets/deepin-meetup-04.AQTWsrIi.jpg",s="/assets/deepin-meetup-05.Di86YKMJ.jpg",u="/assets/deepin-meetup-06.DcnBOce-.jpg",_=JSON.parse('{"title":"成都相聚｜文心飞桨社区 × deepin AI 开发者沙龙圆满落幕","description":"","frontmatter":{"title":"成都相聚｜文心飞桨社区 × deepin AI 开发者沙龙圆满落幕","date":"2026-04-18T00:00:00.000Z","author":{"name":"王凯","github":"onecatcn"}},"headers":[],"relativePath":"posts/deepin-meetup-chengdu.md","filePath":"posts/deepin-meetup-chengdu.md"}'),d={name:"posts/deepin-meetup-chengdu.md"};function g(l,e,c,h,q,m){return i(),a("div",null,[...e[0]||(e[0]=[o('<blockquote><p>4 月 18 日，成都 IFS 高楼之上，一场关于 AI 与国产开源操作系统的碰撞正在发生。</p></blockquote><p>2026 年 4 月 18 日下午，文心飞桨社区与统信 deepin 携手，在成都举办了一场线下 AI 开发者技术沙龙。来自高校、企业和开源社区的 40 余位开发者聚集于成都 IFS 二号楼 43 楼水调歌头会议室，共同探索「操作系统 + 大模型」的技术前沿。</p><p>这是 PFCC（飞桨框架贡献者俱乐部）首次与国产操作系统社区联合举办线下活动，也是飞桨黑客松第十期文心合作伙伴赛道向成都开发者社区的一次深度延伸。</p><figure><img src="'+p+'" alt="活动全体合影"><figcaption>活动全体合影——40+ 开发者齐聚成都 IFS</figcaption></figure><hr><h2 id="百度视角-ai-生态从-框架-到-工具链" tabindex="-1">百度视角：AI 生态从&quot;框架&quot;到&quot;工具链&quot; <a class="header-anchor" href="#百度视角-ai-生态从-框架-到-工具链" aria-label="Permalink to &quot;百度视角：AI 生态从&quot;框架&quot;到&quot;工具链&quot;&quot;">​</a></h2><p>沙龙开场，文心飞桨社区<strong>王师傅</strong>率先登台，带来了一场关于「百度 AI 生态赋能」的深度分享。</p><p>王凯从飞桨深度学习框架的演进讲起，梳理了从底层训练框架到大模型产业工具链的完整路径——包括飞桨深度学习框架、文心大模型、PaddleOCR 等一系列产品。他结合自身经验，将&quot;宏大的 AI 生态&quot;翻译成开发者视角下的具体路径：<strong>可上手、可实践、可创造</strong>。</p><figure><img src="'+n+'" alt="王师傅分享百度 AI 生态"><figcaption>王师傅介绍文心大模型与 PaddleOCR 产品体系</figcaption></figure><hr><h2 id="deepin-视角-操作系统的-智能化转型" tabindex="-1">deepin 视角：操作系统的&quot;智能化转型&quot; <a class="header-anchor" href="#deepin-视角-操作系统的-智能化转型" aria-label="Permalink to &quot;deepin 视角：操作系统的&quot;智能化转型&quot;&quot;">​</a></h2><p>deepin 资深桌面研发工程师<strong>卢桢</strong>的分享将视线拉回到桌面端。</p><p>在《deepin AI OS 应用探索》环节，卢桢没有讲系统底层架构，而是聚焦于<strong>用户行为与 AI 交互</strong>的结合点：当 AI 能力真正融入全局系统，操作系统正在从&quot;工具&quot;悄然演变为&quot;智能助手&quot;。他对全局 AI 交互范式的思考，引发了现场开发者的强烈共鸣。</p><figure><img src="'+r+'" alt="卢桢分享 deepin AI OS 应用探索"><figcaption>deepin 工程师卢桢分享 AI OS 应用探索，现场互动踊跃</figcaption></figure><hr><h2 id="飞桨黑客松深度解析-deepin-赛道通关手册" tabindex="-1">飞桨黑客松深度解析：deepin 赛道通关手册 <a class="header-anchor" href="#飞桨黑客松深度解析-deepin-赛道通关手册" aria-label="Permalink to &quot;飞桨黑客松深度解析：deepin 赛道通关手册&quot;">​</a></h2><p>下午 15:30，活动进入核心环节——飞桨黑客松第十期文心合作伙伴赛道的「deepin 专属赛题讲解」。</p><p>deepin 专家上阵，从两个维度拆解赛题：</p><ul><li><strong>赛事机制</strong>：大赛流程、激励机制（千元现金奖励）、提交要求</li><li><strong>技术方向</strong>：系统级 AI 交互的核心维度、底层接口调用到高层开发思路的具体建议</li></ul><p>对于想参赛但不知道从哪里下手的开发者，这一环节提供了切实的&quot;破题路径&quot;，现场提问踊跃。</p><p>👉 黑客松报名入口：<a href="https://github.com/PaddlePaddle/Paddle/issues/78485" target="_blank" rel="noreferrer">https://github.com/PaddlePaddle/Paddle/issues/78485</a></p><hr><h2 id="闪电演讲-三位开发者-三种成长路径" tabindex="-1">闪电演讲：三位开发者，三种成长路径 <a class="header-anchor" href="#闪电演讲-三位开发者-三种成长路径" aria-label="Permalink to &quot;闪电演讲：三位开发者，三种成长路径&quot;">​</a></h2><p>茶歇结束后，三位社区开发者带来了各具特色的闪电演讲：</p><figure><img src="'+s+'" alt="三位嘉宾闪电演讲"><figcaption>三位闪电演讲嘉宾同台，干货密集、高潮迭起</figcaption></figure><p><strong>水歌</strong>（idea2app 创始人、fCC 成都社区主理人） 《数据驱动的飞书 AI 应用实践》——以真实业务场景为背景，演示如何用 AI 搭建数据驱动的飞书工作流，引发大量&quot;这个我能复用&quot;的实战讨论。</p><p><strong>裴薪宇</strong>（西南交通大学） 《我用 AI 开发了一个 500+ stars 的开源工具：从想法到落地》——以在校学生的视角展示 AI 如何全程赋能一个开源项目的从零到一，让不少开发者重新审视&quot;一个人也能做成事&quot;的可能性。</p><p><strong>程诗杰</strong>（社区极客） 《从路人甲到社区之光的思考与行动》——讲述从一个普通社区参与者，成长为核心贡献者的心路历程，对刚刚踏入开源世界的新人极具感召力。</p><hr><h2 id="_40-极客的惬意下午" tabindex="-1">40+ 极客的惬意下午 <a class="header-anchor" href="#_40-极客的惬意下午" aria-label="Permalink to &quot;40+ 极客的惬意下午&quot;">​</a></h2><p>茶歇与自由交流环节是这场活动能量最密集的时刻。</p><p>参会者向百度专家探讨黑客松参赛思路，与 deepin 团队畅想智能操作系统的未来，与演讲嘉宾深入延展技术话题。来自高校、创业团队和大厂的开发者们在这里相遇，话题从赛题跑到 AI Agent，从飞桨聊到国产 Linux 生态。</p><figure><img src="'+u+'" alt="茶歇自由交流"><figcaption>茶歇交流时刻——开发者们热烈互动，意犹未尽</figcaption></figure><p>成都特有的那种&quot;轻松而不浅薄&quot;的氛围，在这个高楼的下午被诠释得恰到好处。</p><hr><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>这次与统信 deepin 的联合活动，是文心飞桨社区在&quot;AI × 国产操作系统&quot;这一交叉地带的一次有益探索。</p><p>对于 PFCC 来说，它的意义不仅在于一场活动，更在于验证了一种可能：<strong>当国产框架、国产大模型与国产操作系统相遇，开发者社区本身就是最好的&quot;融合实验室&quot;</strong>。</p><p>期待下一站，在你所在的城市见面。</p><hr><p><em>感谢 deepin 社区、idea2app、fCC 成都社区、蜀鸿会对本次活动的支持。</em><em>飞桨黑客松第十期文心合作伙伴赛道仍在火热进行中，欢迎报名参赛！</em></p>',41)])])}const I=t(d,[["render",g]]);export{_ as __pageData,I as default};
